from agent import *from models.products import *def run(context, session):    session.queue(Request('https://www.printershowcase.com/color-laser-printer-reviews.aspx'), process_frontpage, dict())def process_frontpage(data, context, session):    cats = data.xpath("//div[@id='ctl00_pageContent_htmlContent']/a")    for cat in cats:        url = cat.xpath("@href").string()        session.queue(Request(url), process_category, dict(context))def process_category(data, context, session):    breadcrumbs = list()    for breadcrumb in data.xpath("//span[@id='ctl00_breadcrumbContent']/span"):        subcat = breadcrumb.xpath(".//text()").string().strip()        if subcat not in ['Home', '>']:            breadcrumbs.append(subcat)    cat = '|'.join(breadcrumbs)    revs = data.xpath("//div[@class='page-html-content']/a[contains(@href,'Review-')]")    for rev in revs:        url = rev.xpath("@href").string()        session.queue(Request(url), process_review, dict(context, cat=cat, url=url))def process_review(data, context, session):    product = Product()    product.ssid = context['url'].split('/')[-1].replace('.aspx', '').replace('Review-', '')    product.url = context['url']    product.category = context['cat']    title = data.xpath("//span[@id='ctl00_breadcrumbContent']/span[last()]//text()").string()    name = title    if ' - ' in name:        name = name.split(' - ')[1]    product.name = name    review = Review()    review.type = "pro"    review.title = title    review.url = product.url    review.ssid = product.ssid    excerpt = data.xpath("//div[@id='ctl00_pageContent_htmlContent']//text()").string(multiple=True)    if excerpt:        conclusion = excerpt.split('The Bottom Line:')[-1].strip()        if conclusion:            review.add_property(type='conclusion', value=conclusion)            excerpt = excerpt.split('The Bottom Line:')[0].strip()        excerpt = excerpt.replace('In Short:', '').strip()        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))        product.reviews.append(review)        session.emit(product)